                        <div key={rule.id} className="flex items-center gap-2 text-sm">
                          <SeverityBadge severity={rule.severity} />
                          <code className="font-mono">{rule.pattern}</code>
                          <span className="text-muted-foreground">- {rule.description}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </AccordionContent>
              </AccordionItem>
            ))}
          </Accordion>
        </CardContent>
      </Card>
    </div>
  );
}
