  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (packId: string) =>
      api.post(`/dcg/packs/${packId}/enable`).json(),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["dcg"] });
    },
  });
}

export function useDisablePack() {
